  KEY `security_ip_bans_ip_index` (`ip`),
  KEY `security_ip_bans_banned_until_index` (`banned_until`),
  CONSTRAINT `security_ip_bans_created_by_foreign` FOREIGN KEY (`created_by`) REFERENCES `users` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
