--
-- Table structure for table `users`
--

DROP TABLE IF EXISTS `users`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `users` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `public_id` varchar(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `email` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `match_type` varchar(3) COLLATE utf8mb4_unicode_ci NOT NULL,
  `birthdate` date NOT NULL,
  `gender` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL,
  `looking_for` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL,
  `location` varchar(120) COLLATE utf8mb4_unicode_ci NOT NULL,
  `postcode` varchar(5) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `district` varchar(120) COLLATE utf8mb4_unicode_ci NOT NULL,
  `username` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL,
  `privacy_accepted_at` timestamp NULL DEFAULT NULL,
  `moderation_warned_at` timestamp NULL DEFAULT NULL,
  `moderation_warn_count` int unsigned NOT NULL DEFAULT '0',
  `moderation_blocked_at` timestamp NULL DEFAULT NULL,
  `moderation_blocked_until` timestamp NULL DEFAULT NULL,
  `moderation_blocked_permanent` tinyint(1) NOT NULL DEFAULT '0',
  `moderation_blocked_reason` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `email_verified_at` timestamp NULL DEFAULT NULL,
  `registration_ip` varchar(45) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `registration_ip_at` timestamp NULL DEFAULT NULL,
  `last_login_ip` varchar(45) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `last_login_ip_at` timestamp NULL DEFAULT NULL,
  `password` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `password_changed_at` timestamp NULL DEFAULT NULL,
  `remember_token` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `is_protected_admin` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'DB-only flag: protected superadmin cannot be downgraded or deleted',
  `is_frozen` tinyint(1) NOT NULL DEFAULT '0',
  `banned_at` datetime DEFAULT NULL,
  `moderator_sections` json DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `users_email_unique` (`email`),
  UNIQUE KEY `users_public_id_unique` (`public_id`),
  UNIQUE KEY `users_username_unique` (`username`),
  KEY `users_moderation_blocked_permanent_index` (`moderation_blocked_permanent`),
  KEY `users_moderation_blocked_until_index` (`moderation_blocked_until`)
) ENGINE=InnoDB AUTO_INCREMENT=9 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

